// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {


	if(isLoading){ 
		showHideFields();
		return;
	}

	//RJ - STRY0065465 - had to take old value vs new value off.
	//     If you set it to a value that hide fields, but the original did not, the fields are hidden, but don't get redisplayed
	// 
	//if(newValue!=oldValue){ 
		showHideFields();
	//}

	function showHideFields (){
		var tasker_type =  g_form.getDisplayValue('tasker_type');
		var isStandard = tasker_type == 'Standard';
		var isAcknowledgement = tasker_type ==  'Acknowledgement';
		var isInformation_only = tasker_type == 'Information Only';

		//Duration fields
		g_form.setDisplay("duration", (!isAcknowledgement && !isInformation_only));
		//Assignment fields
		g_form.setDisplay("u_reviewer", (!isAcknowledgement && !isInformation_only));
		//Risk section
		g_form.setSectionDisplay('risk', (!isAcknowledgement && !isInformation_only));

		//Response & Reviewer Decision section - STRY0095887 - changed to standard only 
		g_form.setSectionDisplay('response_reviewerdecision', (isStandard));
		// Review Required
		g_form.setDisplay("provide_response", isStandard);

	}
}
